// =====================================================================
// utils/pdf-export.js
// تصدير أي جدول HTML إلى تقرير PDF منسَّق وملوَّن بترويسة رسمية باسم
// الأمانة العامة (بشعارها الرسمي) وتذييل اعتماد الأمين العام. يعتمد
// على مكتبتي html2canvas وjsPDF (مُحمَّلتين كـ <script> عاديتين في
// index.html).
//
// آلية العمل: نبني حاوية HTML مخفية بنفس تنسيق التطبيق (بما في ذلك خط
// Cairo العربي)، نلتقطها كصورة عالية الدقة عبر html2canvas (وهو ما
// يضمن عرض النص العربي بشكل سليم تماماً كما يظهر في المتصفح، بخلاف
// محاولة كتابة نص عربي مباشرة بمكتبات PDF التي لا تدعم تشكيل الحروف
// العربية أصلاً)، ثم نقسّم البيانات مسبقاً لصفحات A4 مع تكرار رأس
// الجدول في كل صفحة.
// =====================================================================

import { showToast } from './toast.js';
import { escapeHtml } from './ui-helpers.js';

const ACTIONS_COLUMN_LABELS = ["إجراءات", "إجراء"];
const ORG_NAME = "الأمانة العامة لروابط مستخدمي المياه بمحافظة الجيزة";
const APPROVER_NAME = "الحج صافي ضو الربيعي";
const APPROVER_TITLE = "الأمين العام";

// شعار الأمانة العامة الرسمي — مُضمَّن كـ base64 مباشرة (بدل الإشارة
// لملف خارجي assets/logo-authority.png) لضمان ظهوره دائماً في التقرير
// المُصدَّر بلا أي احتمال لتأخر تحميل أو مشاكل مسار الملف عند التقاط
// html2canvas للصورة.
const ORG_LOGO_BASE64 = "data:image/png;base64,";

// ============ ألوان الحالات — نفس ألوان البادجات الحية في التطبيق ============
// المشكلة التي يحلّها هذا: استخراج بيانات الجدول للتصدير كان يعتمد على
// textContent فقط، فتُفقَد كل ألوان الحالة (البادجات الملوّنة) التي هي
// أهم إشارة بصرية في تقرير كهذا (تحديد الترع/المساقي "الحرجة" أو
// "المحتاجة تطهير" فوراً دون قراءة كل صف). الحل: تعريف نفس خريطة
// الألوان المستخدمة في الجداول الحية، وتطبيقها كبادج ملوّن في عمود
// "الحالة" تحديداً + تظليل خفيف للصف كله عند الحالات الحرجة، بدلاً من
// نص عادي بلا أي تمييز.
const STATUS_STYLES = {
    "تحتاج للتطهير": { bg: "#7a1c1c", fg: "#ffffff", rowTint: "#fdf0ef" },
    "حرجة": { bg: "#7a1c1c", fg: "#ffffff", rowTint: "#fdf0ef" },
    "قيد العمل": { bg: "#fef9eb", fg: "#8a5a00" },
    "جاري التطهير": { bg: "#fef9eb", fg: "#8a5a00" },
    "قيد المتابعة": { bg: "#fef9eb", fg: "#8a5a00" },
    "تم التطهير": { bg: "#edf7f2", fg: "#1f5c3f" },
    "تم الحسم": { bg: "#edf7f2", fg: "#1f5c3f" },
    "لا تحتاج لتطهير": { bg: "#eaf4fa", fg: "#164a63" },
    "جديد": { bg: "#eaf4fa", fg: "#164a63" },
};

function extractTableData(tableId) {
    const table = document.getElementById(tableId);
    if (!table) return null;
    const headerCells = Array.from(table.querySelectorAll("thead th")).map(th => th.textContent.trim());
    const actionsIndex = headerCells.findIndex(h => ACTIONS_COLUMN_LABELS.includes(h));
    const headers = headerCells.filter((_, i) => i !== actionsIndex);

    const rows = Array.from(table.querySelectorAll("tbody tr")).map(tr => {
        const cells = Array.from(tr.children);
        return cells
            .filter((_, i) => i !== actionsIndex)
            .map(td => td.textContent.trim());
    }).filter(r => r.length && r.some(c => c)); // تجاهل صفوف "لا توجد بيانات"/التحميل

    return { headers, rows };
}

// ============ بناء رأس/تذييل الصفحة حسب موضعها ============
function buildHeaderBlock(reportTitle, isFirstPage) {
    const now = new Date();
    const dateStr = now.toLocaleDateString("ar-EG", { year: "numeric", month: "long", day: "numeric" });
    const timeStr = now.toLocaleTimeString("ar-EG", { hour: "2-digit", minute: "2-digit" });

    if (isFirstPage) {
        return `
        <div style="display:flex; align-items:center; justify-content:space-between; border-bottom:4px solid #0f4c46; padding-bottom:16px; margin-bottom:20px;">
            <div style="display:flex; align-items:center; gap:14px;">
                <img src="${ORG_LOGO_BASE64}" alt="شعار الأمانة العامة" style="width:58px; height:58px; object-fit:contain;" />
                <div>
                    <div style="font-size:20px; font-weight:900; color:#0f4c46;">${ORG_NAME}</div>
                    <div style="font-size:13px; color:#b9692e; font-weight:700; margin-top:2px;">منصة زِمام الرقمية — محافظة الجيزة</div>
                </div>
            </div>
            <div style="text-align:left; font-size:12px; color:#5c665a;">
                <div>تاريخ التقرير: ${dateStr}</div>
                <div>وقت الإصدار: ${timeStr}</div>
            </div>
        </div>
        <div style="font-size:17px; font-weight:900; color:#1a2219; margin-bottom:16px;">📋 ${escapeHtml(reportTitle)}</div>`;
    }
    return `
        <div style="display:flex; align-items:center; justify-content:space-between; border-bottom:2px solid #cfead2; padding-bottom:10px; margin-bottom:16px;">
            <div style="font-size:13px; font-weight:800; color:#0f4c46;">${ORG_NAME} — تابع: ${escapeHtml(reportTitle)}</div>
            <div style="font-size:11px; color:#5c665a;">${dateStr}</div>
        </div>`;
}

function buildTableBlock(headers, rows) {
    const statusColIndex = headers.findIndex(h => h === "الحالة");
    const headHtml = headers.map(h =>
        `<th style="background-color:#0f4c46; color:#ffffff; padding:10px 8px; border:1px solid #0d3f3a; font-weight:800; text-align:right;">${escapeHtml(h)}</th>`
    ).join("");
    const rowsHtml = rows.map((r, i) => {
        const statusValue = statusColIndex >= 0 ? r[statusColIndex] : null;
        const statusStyle = statusValue ? STATUS_STYLES[statusValue] : null;
        const baseBg = statusStyle?.rowTint || (i % 2 === 0 ? "#ffffff" : "#f4efe3");
        const cells = r.map((c, ci) => {
            if (ci === statusColIndex && statusStyle) {
                return `<td style="background-color:${baseBg}; padding:8px; border:1px solid #e3d9be; text-align:right;">
                    <span style="display:inline-block; background-color:${statusStyle.bg}; color:${statusStyle.fg}; font-weight:800; font-size:11px; padding:3px 10px; border-radius:10px;">${escapeHtml(c)}</span>
                </td>`;
            }
            return `<td style="background-color:${baseBg}; padding:8px; border:1px solid #e3d9be; text-align:right; color:#1a2219;">${escapeHtml(c)}</td>`;
        }).join("");
        return `<tr>${cells}</tr>`;
    }).join("");
    return `<table style="width:100%; border-collapse:collapse; font-size:13px;">
            <thead><tr>${headHtml}</tr></thead>
            <tbody>${rowsHtml}</tbody>
        </table>`;
}

function buildLegend(headers, rows) {
    const statusColIndex = headers.findIndex(h => h === "الحالة");
    if (statusColIndex < 0) return "";
    const present = [...new Set(rows.map(r => r[statusColIndex]).filter(Boolean))]
        .filter(v => STATUS_STYLES[v]);
    if (present.length === 0) return "";
    const chips = present.map(v => {
        const s = STATUS_STYLES[v];
        return `<span style="display:inline-flex; align-items:center; gap:6px; margin-left:16px;">
            <span style="width:12px; height:12px; border-radius:4px; background-color:${s.bg}; display:inline-block; ${s.fg === "#ffffff" ? "" : "border:1px solid #d8cfa8;"}"></span>
            <span style="font-size:11px; color:#5c665a;">${escapeHtml(v)}</span>
        </span>`;
    }).join("");
    return `<div style="margin-top:14px; padding-top:10px; border-top:1px dashed #d8cfa8;">${chips}</div>`;
}

// ============ نسبة الإنجاز (تطهير/جاري التطهير) في تذييل التقرير ============
// المطلوب: شريط ملوّن في آخر كل تقرير مُصدَّر يوضح كام بالمية اتطهّر
// وكام جاري تطهيره من إجمالي عدد المجاري المائية (أو البلاغات، حسب
// الجدول المُصدَّر) — بدل ما المدير يعدّ الصفوف بنفسه أو يرجع للشاشة.
// يعمل تلقائياً على أي جدول فيه عمود "الحالة" (المساقي، الترع،
// البلاغات) بتصنيف كل قيمة حالة على واحدة من 4 مجموعات عامة، ويختفي
// تلقائياً لو الجدول المُصدَّر ملوش عمود حالة أصلاً (مثل جدول الأعضاء).
const COMPLETION_BUCKETS = [
    { key: "done", label: "تم التطهير", icon: "✅", color: "#1f8a54", statuses: ["تم التطهير", "تم الحسم"] },
    { key: "progress", label: "جاري التطهير", icon: "⚙️", color: "#d9950f", statuses: ["جاري التطهير", "قيد العمل", "قيد المتابعة"] },
    { key: "attention", label: "تحتاج تدخّل", icon: "⚠️", color: "#b3261e", statuses: ["تحتاج للتطهير", "حرجة", "جديد"] },
    { key: "na", label: "لا تحتاج", icon: "🔵", color: "#3170a6", statuses: ["لا تحتاج لتطهير"] },
];

function buildCompletionSummary(headers, rows) {
    const statusColIndex = headers.findIndex(h => h === "الحالة");
    if (statusColIndex < 0 || rows.length === 0) return "";

    const total = rows.length;
    const counts = COMPLETION_BUCKETS.map(b => ({
        ...b,
        count: rows.filter(r => b.statuses.includes(r[statusColIndex])).length,
    })).filter(b => b.count > 0);
    if (counts.length === 0) return "";

    const barSegments = counts.map(b =>
        `<div style="width:${(b.count / total * 100).toFixed(1)}%; background-color:${b.color};" title="${b.label}"></div>`
    ).join("");

    const statsLines = counts.map(b => {
        const pct = Math.round((b.count / total) * 100);
        return `<div style="display:flex; align-items:center; gap:8px; font-size:12px; color:#1a2219;">
            <span style="width:12px; height:12px; border-radius:3px; background-color:${b.color}; display:inline-block; flex-shrink:0;"></span>
            <span style="font-weight:800;">${b.icon} ${b.label}:</span>
            <span>${b.count} من ${total} (${pct}٪)</span>
        </div>`;
    }).join("");

    return `
        <div style="margin-top:18px; padding:14px 16px; background-color:#f7f5ec; border:1px solid #e3d9be; border-radius:10px;">
            <div style="font-size:13px; font-weight:900; color:#0f4c46; margin-bottom:10px;">📊 نسبة الإنجاز</div>
            <div style="display:flex; width:100%; height:16px; border-radius:8px; overflow:hidden; background-color:#e3d9be; margin-bottom:12px;">
                ${barSegments}
            </div>
            <div style="display:flex; flex-wrap:wrap; gap:14px;">${statsLines}</div>
        </div>`;
}

function buildSignatureBlock(headers, rows, totalRows) {
    return `
        <div style="margin-top:10px; font-size:11px; color:#5c665a;">إجمالي عدد السجلات: ${totalRows}</div>
        ${buildCompletionSummary(headers, rows)}
        ${buildLegend(headers, rows)}
        <div style="margin-top:44px; display:flex; justify-content:flex-end;">
            <div style="text-align:center; min-width:260px;">
                <div style="font-size:13px; color:#5c665a; font-weight:700; margin-bottom:44px;">يعتمد ${APPROVER_TITLE}</div>
                <div style="border-top:2px solid #1a2219; padding-top:8px;">
                    <div style="font-size:15px; font-weight:900;">${APPROVER_NAME}</div>
                </div>
            </div>
        </div>`;
}

function buildPageHtml(headers, rows, reportTitle, isFirstPage, isLastPage, totalRows, allRows) {
    return `
    <div style="direction:rtl; font-family:'Cairo',sans-serif; width:1000px; background-color:#ffffff; color:#1a2219; padding:36px;">
        ${buildHeaderBlock(reportTitle, isFirstPage)}
        ${buildTableBlock(headers, rows)}
        ${isLastPage ? buildSignatureBlock(headers, allRows, totalRows) : ""}
    </div>`;
}

// عدد الصفوف التقريبي الذي يسع صفحة A4 واحدة بأمان (بتقدير متحفّظ يراعي
// وجود الترويسة الكاملة في الصفحة الأولى فقط) — تفضيل صفحات أكثر
// وأكثر أماناً من الانتظار لتقدير مثالي قد يتسبب في قطع صف منتصف صفحة.
const ROWS_FIRST_PAGE = 18;
const ROWS_OTHER_PAGE = 26;

function chunkRows(rows) {
    const chunks = [];
    let i = 0;
    let first = true;
    while (i < rows.length) {
        const size = first ? ROWS_FIRST_PAGE : ROWS_OTHER_PAGE;
        chunks.push(rows.slice(i, i + size));
        i += size;
        first = false;
    }
    return chunks;
}

export async function exportTableToPDF(tableId, reportTitle, filename) {
    if (typeof html2canvas === "undefined" || typeof window.jspdf === "undefined") {
        showToast("⚠️ تعذر تحميل مكتبة PDF، تأكد من اتصالك بالإنترنت وحاول مرة أخرى.");
        return;
    }
    const data = extractTableData(tableId);
    if (!data || data.rows.length === 0) {
        showToast("⚠️ لا توجد بيانات لتصديرها.");
        return;
    }
    const pageChunks = chunkRows(data.rows);

    const container = document.createElement("div");
    container.style.position = "fixed";
    container.style.top = "0";
    container.style.left = "-10000px";
    container.style.zIndex = "-1";
    document.body.appendChild(container);

    try {
        showToast(`⏳ جاري تجهيز ملف PDF (${pageChunks.length > 1 ? pageChunks.length + " صفحات" : "صفحة واحدة"})...`);
        const { jsPDF } = window.jspdf;
        const pdf = new jsPDF("p", "mm", "a4");
        const pageWidth = pdf.internal.pageSize.getWidth();

        for (let p = 0; p < pageChunks.length; p++) {
            const isFirstPage = p === 0;
            const isLastPage = p === pageChunks.length - 1;
            container.innerHTML = buildPageHtml(data.headers, pageChunks[p], reportTitle, isFirstPage, isLastPage, data.rows.length, data.rows);
            const canvas = await html2canvas(container.firstElementChild, { scale: 2, useCORS: true, backgroundColor: "#ffffff" });
            const imgWidth = pageWidth;
            const imgHeight = (canvas.height * imgWidth) / canvas.width;
            const imgData = canvas.toDataURL("image/png");
            if (p > 0) pdf.addPage();
            pdf.addImage(imgData, "PNG", 0, 0, imgWidth, imgHeight);
            // ترقيم الصفحات
            pdf.setFontSize(9);
            pdf.setTextColor(120, 120, 120);
            pdf.text(`${p + 1} / ${pageChunks.length}`, pageWidth / 2, pdf.internal.pageSize.getHeight() - 6, { align: "center" });
        }

        pdf.save(`${filename}_${new Date().toISOString().slice(0, 10)}.pdf`);
        showToast("✅ تم تنزيل التقرير بصيغة PDF.");
    } catch (e) {
        console.error(e);
        showToast("⚠️ تعذر إنشاء ملف PDF، حاول مرة أخرى.");
    } finally {
        document.body.removeChild(container);
    }
}
